const { Pool } = require('pg');
require('dotenv').config();

// Create a new pool of connections with the database
const pool = new Pool({
    user: process.env.PG_SUPERUSER,  // Uses environment variable to store superuser credentials
    host: process.env.PG_HOST,        // Uses environment variable to store host address
    database: process.env.PG_DATABASE,// Uses environment variable to store the name of your database
    password: process.env.PG_PASSWORD,// Uses environment variable to store superuser's password
    port: process.env.PG_PORT,        // Uses environment variable to store the port number
});

pool.connect((err, client) => {
  if (err) throw err;
  
  console.log("Connected to Database");

  client.release();
})

// Create
const createTable = async(req, res) => {
    const tableName = req.params.tableName;
    
    pool.query(`CREATE TABLE ${tableName}()`, (err, result) => {
        if (err) throw err;
        
        res.status(201).json({ message: "Table created" });
    })
};

// Read 
